import os
import time
import pytest
import can

BCM_STATUS_ID = 0x100

@pytest.fixture(scope="module")
def can_bus():
    bus = can.interface.Bus(interface=os.getenv('CAN_INTERFACE', 'vector'), channel=0, bitrate=500000)
    yield bus
    bus.shutdown()

def get_hazard_status(data_bytes: bytes) -> int:
    return (data_bytes[0] >> 0) & 0x01

def collect_bcm_messages(bus, duration_sec=1.0):
    msgs = []
    start = time.time()
    while time.time() - start < duration_sec:
        msg = bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == BCM_STATUS_ID: msgs.append(msg)
    return msgs

